// Some portions generated by Codex
package org.eclipse.rdf4j.sail.lmdb.sketch;

import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertNotNull;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.ArrayList;
import java.util.List;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Resource;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.ValueFactory;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.ListMemberOperator;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.ValueConstant;
import org.eclipse.rdf4j.query.algebra.Var;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

class SketchBasedJoinEstimatorOmniSurfaceRetentionTest {

	private static final ValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI TYPE = VF.createIRI("urn:omni-retention:type");
	private static final IRI ENTITY = VF.createIRI("urn:omni-retention:Entity");
	private static final IRI EDGE = VF.createIRI("urn:omni-retention:edge");
	private static final IRI FLAG = VF.createIRI("urn:omni-retention:flag");
	private static final IRI STATUS = VF.createIRI("urn:omni-retention:status");
	private static final Value ACTIVE = VF.createLiteral("active");
	private static final Value CLOSED = VF.createLiteral("closed");

	private final List<SketchBasedJoinEstimator> estimators = new ArrayList<>();
	private StubSketchStatementSource store;
	private SketchBasedJoinEstimator estimator;

	@BeforeEach
	void setUp() {
		store = new StubSketchStatementSource();
		for (int index = 0; index < 64; index++) {
			Resource root = VF.createIRI("urn:omni-retention:root:" + index);
			Resource middle = VF.createIRI("urn:omni-retention:middle:" + index);
			store.add(VF.createStatement(root, TYPE, ENTITY));
			store.add(VF.createStatement(root, EDGE, middle));
			store.add(VF.createStatement(middle, FLAG, index < 32 ? ACTIVE : CLOSED));
			store.add(VF.createStatement(root, STATUS, index < 16 ? CLOSED : ACTIVE));
		}
		estimator = track(new SketchBasedJoinEstimator(store, omniConfig()));
		estimator.rebuild();
	}

	@AfterEach
	void tearDown() {
		for (SketchBasedJoinEstimator current : estimators) {
			current.close();
		}
	}

	@Test
	void subjectStarAndBridgeChainRetainBindingsWitnessesAndSteps() {
		StatementPattern rootType = fixedObjectPattern("root", TYPE, ENTITY);
		StatementPattern rootStatus = fixedObjectPattern("root", STATUS, ACTIVE);
		StatementPattern rootEdge = pattern("root", EDGE, "middle");
		StatementPattern middleFlag = fixedObjectPattern("middle", FLAG, ACTIVE);

		OmniSketchSurfaceEstimate subjectStar = estimator.estimateSubjectStarOmniSurface(
				List.of(rootType, rootStatus), "root");
		OmniSketchSurfaceEstimate bridgeChain = estimator.estimateOmniBridgeChain(
				List.of(rootType, rootEdge, middleFlag), Set.of());

		assertCompleteSurface(subjectStar, "root", "subject-star");
		assertCompleteSurface(bridgeChain, "middle", "bridge-chain");
	}

	@Test
	void bridgeProbeEmbedsCompleteOmniSurface() {
		StatementPattern rootType = fixedObjectPattern("root", TYPE, ENTITY);
		StatementPattern rootEdge = pattern("root", EDGE, "middle");

		OmniBridgeProbeEstimate probe = estimator.estimateOmniBridgeProbe(List.of(rootType), rootEdge, 64.0d)
				.orElseThrow();

		assertCompleteSurface(probe.omniSurface(), "middle", "bridge-probe");
	}

	@Test
	void finiteFilterEmbedsCompleteOmniSurface() {
		StatementPattern rootStatus = pattern("root", STATUS, "status");
		ListMemberOperator condition = new ListMemberOperator();
		condition.addArgument(new Var("status"));
		condition.addArgument(new ValueConstant(ACTIVE));

		OmniFiniteFilterProbeEstimate probe = estimator.estimateOmniFiniteFilterProbe(rootStatus, condition, 64.0d)
				.orElseThrow();

		assertCompleteSurface(probe.omniSurface(), "root", "finite-filter-probe");
	}

	@Test
	void correlatedSemiAndAntiProbesEmbedCompleteOmniSurfaces() {
		StatementPattern rootType = fixedObjectPattern("root", TYPE, ENTITY);
		StatementPattern closedStatus = fixedObjectPattern("root", STATUS, CLOSED);

		OmniCorrelatedProbeEstimate semi = estimator
				.estimateOmniCorrelatedSemiProbe(rootType, closedStatus, Set.of("root"), 64.0d)
				.orElseThrow();
		OmniCorrelatedProbeEstimate anti = estimator
				.estimateOmniCorrelatedAntiProbe(rootType, closedStatus, Set.of("root"), 64.0d)
				.orElseThrow();

		assertCompleteSurface(semi.omniSurface(), "root", "correlated-semi-probe");
		assertCompleteSurface(anti.omniSurface(), "root", "correlated-anti-probe");
	}

	private static void assertCompleteSurface(OmniSketchSurfaceEstimate surface, String bindingName,
			String surfaceKind) {
		assertNotNull(surface);
		assertTrue(surface.bindings().containsKey(bindingName), () -> "missing binding evidence: " + surface);
		assertNotNull(surface.bindings().get(bindingName).witnesses());
		assertTrue(surface.bindings().get(bindingName).witnessCount() > 0);
		assertFalse(surface.steps().isEmpty(), () -> "missing step evidence: " + surface);
		assertTrue(surface.steps().stream().anyMatch(step -> surfaceKind.equals(step.operatorKind())),
				() -> "missing " + surfaceKind + " step: " + surface.steps());
	}

	private SketchBasedJoinEstimator track(SketchBasedJoinEstimator current) {
		estimators.add(current);
		return current;
	}

	private static StatementPattern pattern(String subjectName, IRI predicate, String objectName) {
		return new StatementPattern(new Var(subjectName), new Var("predicate", predicate), new Var(objectName));
	}

	private static StatementPattern fixedObjectPattern(String subjectName, IRI predicate, Value object) {
		return new StatementPattern(new Var(subjectName), new Var("predicate", predicate), new Var("object", object));
	}

	private static SketchBasedJoinEstimator.Config omniConfig() {
		return SketchBasedJoinEstimator.Config.defaults()
				.withSketchStrategy(SketchBasedJoinEstimator.SketchStrategy.OMNI)
				.withNominalEntries(4096)
				.withSubjectBucketCount(4096)
				.withPredicateBucketCount(64)
				.withObjectBucketCount(4096)
				.withContextBucketCount(16)
				.withEstimateCacheSeconds(0)
				.withThrottleEveryN(1)
				.withThrottleMillis(0)
				.withRefreshSleepMillis(5);
	}
}
